import { useEffect, useRef } from 'react';

/**
 * Attaches an IntersectionObserver to the returned ref.
 * `callback` fires whenever the element enters the viewport.
 * `threshold` is stable — pass a primitive, not an object literal, to avoid re-runs.
 */
const useIntersectionObserver = (callback, { threshold = 0.1, rootMargin = '0px' } = {}) => {
  const ref = useRef(null);
  const callbackRef = useRef(callback);

  // Keep callbackRef current without re-running the effect
  useEffect(() => {
    callbackRef.current = callback;
  }, [callback]);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          callbackRef.current();
          observer.disconnect(); // fire once only
        }
      },
      { threshold, rootMargin }
    );

    observer.observe(el);

    // Fallback: if element is already in viewport on mount, browsers may not
    // fire the initial callback — check manually after a short delay
    const fallbackTimer = setTimeout(() => {
      const rect = el.getBoundingClientRect();
      const inViewport =
        rect.top < window.innerHeight &&
        rect.bottom > 0 &&
        rect.width > 0 &&
        rect.height > 0;
      if (inViewport) {
        callbackRef.current();
        observer.disconnect();
      }
    }, 200);

    return () => {
      observer.disconnect();
      clearTimeout(fallbackTimer);
    };
  // Only re-observe if threshold/rootMargin change, not callback
  }, [threshold, rootMargin]);

  return ref;
};

export default useIntersectionObserver;
